SCENARIOS = [COLONIAL_PIPELINE, SOLARWINDS, MGM_GRAND, LOG4SHELL, NHS_WANNACRY]


async def seed():
    from sqlalchemy import select as _select
    async with SessionLocal() as session:
        added = 0
        for data in SCENARIOS:
            ref = data.get("source_reference")
            existing = await session.execute(
                _select(Scenario).where(Scenario.source_reference == ref)
            )
            if existing.scalar_one_or_none():
                print(f"  skip (exists): {data['title']}")
                continue
            scenario = Scenario(**data)
            session.add(scenario)
            added += 1
        await session.commit()
        print(f"Seeded {added} new scenarios ({len(SCENARIOS) - added} already existed).")


if __name__ == "__main__":
    asyncio.run(seed())
